dashboard.definition:
{
    "dataSources": {
        "ds_telemetry_signal_lock": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup telemetry_signal.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | stats latest(signal_dbm) as value | eval label=\"Signal Lock\", unit=\"dBm\""
            },
            "name": "Signal Lock KPI"
        },
        "ds_telemetry_data_rate": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup telemetry_signal.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | stats latest(data_rate_kbps) as value | eval label=\"Data Rate\", unit=\"kbps\""
            },
            "name": "Data Rate KPI"
        },
        "ds_telemetry_latency": {
            "type": "ds.search",
            "options": {
                "query": "| makeresults | eval value=round(random()%200+50,0), label=\"Latency\", unit=\"ms\""
            },
            "name": "Latency KPI"
        },
        "ds_telemetry_ber": {
            "type": "ds.search",
            "options": {
                "query": "| makeresults | eval value=round(random()%10,2)/1000, label=\"BER\", unit=\"\""
            },
            "name": "Bit Error Rate KPI"
        },
        "ds_signal_waveform": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup telemetry_signal.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | table _time signal_dbm data_rate_kbps"
            },
            "name": "Signal Waveform"
        },
        "ds_radar_sweep": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup ground_stations.csv"
            },
            "name": "Radar Sweep"
        },
        "ds_particle_timeline_comm": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup comm_events.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\""
            },
            "name": "Comm Particle Timeline"
        },
        "ds_orbital_altitude": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup orbital_params.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | stats latest(altitude_km) as value | eval label=\"Altitude\", unit=\"km\""
            },
            "name": "Altitude KPI"
        },
        "ds_orbital_velocity": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup orbital_params.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | stats latest(velocity_kms) as value | eval label=\"Velocity\", unit=\"km/s\""
            },
            "name": "Velocity KPI"
        },
        "ds_orbital_inclination": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup orbital_params.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | stats latest(inclination_deg) as value | eval label=\"Inclination\", unit=\"deg\""
            },
            "name": "Inclination KPI"
        },
        "ds_orbital_period": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup orbital_params.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | stats latest(period_min) as value | eval label=\"Period\", unit=\"min\""
            },
            "name": "Period KPI"
        },
        "ds_radial_orbit": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup orbital_params.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | stats latest(orbit_phase_deg) as phase, latest(altitude_km) as alt, latest(velocity_kms) as vel, latest(periapsis_km) as peri, latest(apoapsis_km) as apo"
            },
            "name": "Radial Orbit"
        },
        "ds_arc_fuel": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup fuel_budget.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | head 1"
            },
            "name": "Arc Fuel Meter"
        },
        "ds_particle_timeline_maneuver": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup maneuver_events.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\""
            },
            "name": "Maneuver Particle Timeline"
        },
        "ds_systems_power": {
            "type": "ds.search",
            "options": {
                "query": "| makeresults | eval value=round(random()%800+1200,0), label=\"Power Draw\", unit=\"W\""
            },
            "name": "Power Draw KPI"
        },
        "ds_systems_thermal": {
            "type": "ds.search",
            "options": {
                "query": "| makeresults | eval value=round(random()%15+18,1), label=\"Thermal Avg\", unit=\"°C\""
            },
            "name": "Thermal Avg KPI"
        },
        "ds_systems_o2": {
            "type": "ds.search",
            "options": {
                "query": "| makeresults | eval value=round(random()%5+20,1), label=\"O₂ Level\", unit=\"%\""
            },
            "name": "O2 Level KPI"
        },
        "ds_systems_crew": {
            "type": "ds.search",
            "options": {
                "query": "| makeresults | eval value=4, label=\"Crew Status\", unit=\"nominal\""
            },
            "name": "Crew Status KPI"
        },
        "ds_hex_health": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup subsystem_health.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | stats latest(status) as status, sparkline(avg(health_pct),1h) as trend by subsystem"
            },
            "name": "Hex Health Grid"
        },
        "ds_alert_waterfall": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup alerts.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | sort -_time | head 20"
            },
            "name": "Alert Waterfall"
        },
        "ds_power_waveform": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup power_telemetry.csv | where mission_id=\"$mission_filter$\" OR \"$mission_filter$\"=\"*\" | rename voltage as amplitude | table _time amplitude"
            },
            "name": "Power Bus Waveform"
        }
    },
    "defaults": {
        "dataSources": {
            "ds.search": {
                "options": {
                    "queryParameters": {
                        "earliest": "$global_time.earliest$",
                        "latest": "$global_time.latest$"
                    }
                }
            }
        }
    },
    "inputs": {
        "input_timerange": {
            "type": "input.timerange",
            "options": {
                "token": "global_time",
                "defaultValue": "-24h,now"
            },
            "title": "Time Range"
        },
        "input_mission": {
            "type": "input.dropdown",
            "options": {
                "token": "mission_filter",
                "defaultValue": "*",
                "items": [
                    {"label": "All", "value": "*"},
                    {"label": "ARTEMIS-II", "value": "ARTEMIS-II"},
                    {"label": "ISS-EXP70", "value": "ISS-EXP70"},
                    {"label": "JWST", "value": "JWST"},
                    {"label": "OSIRIS-APEX", "value": "OSIRIS-APEX"}
                ]
            },
            "title": "Mission"
        }
    },
    "visualizations": {
        "viz_signal_lock_orb": {
            "type": "nasa_mission_control.kpi_orb",
            "options": {
                "nasa_mission_control.kpi_orb.valueField": "value",
                "nasa_mission_control.kpi_orb.unitField": "unit",
                "nasa_mission_control.kpi_orb.labelField": "label",
                "nasa_mission_control.kpi_orb.orbColor": "#00E5A0",
                "nasa_mission_control.kpi_orb.warnThreshold": "-80",
                "nasa_mission_control.kpi_orb.criticalThreshold": "-100",
                "nasa_mission_control.kpi_orb.orbSize": "medium",
                "nasa_mission_control.kpi_orb.showUnit": "true",
                "nasa_mission_control.kpi_orb.showLabel": "true",
                "nasa_mission_control.kpi_orb.showHalo": "true",
                "nasa_mission_control.kpi_orb.decimals": "1",
                "nasa_mission_control.kpi_orb.themeMode": "dark",
                "nasa_mission_control.kpi_orb.showEntrance": "true",
                "nasa_mission_control.kpi_orb.flashCritical": "true",
                "nasa_mission_control.kpi_orb.showHoverEffect": "true",
                "nasa_mission_control.kpi_orb.animationSpeed": "normal"
            },
            "dataSources": {
                "primary": "ds_telemetry_signal_lock"
            },
            "title": "Signal Lock"
        },
        "viz_data_rate_orb": {
            "type": "nasa_mission_control.kpi_orb",
            "options": {
                "nasa_mission_control.kpi_orb.valueField": "value",
                "nasa_mission_control.kpi_orb.unitField": "unit",
                "nasa_mission_control.kpi_orb.labelField": "label",
                "nasa_mission_control.kpi_orb.orbColor": "#00B4FF",
                "nasa_mission_control.kpi_orb.warnThreshold": "500",
                "nasa_mission_control.kpi_orb.criticalThreshold": "100",
                "nasa_mission_control.kpi_orb.orbSize": "medium",
                "nasa_mission_control.kpi_orb.showUnit": "true",
                "nasa_mission_control.kpi_orb.showLabel": "true",
                "nasa_mission_control.kpi_orb.showHalo": "true",
                "nasa_mission_control.kpi_orb.decimals": "0",
                "nasa_mission_control.kpi_orb.themeMode": "dark",
                "nasa_mission_control.kpi_orb.showEntrance": "true",
                "nasa_mission_control.kpi_orb.flashCritical": "true",
                "nasa_mission_control.kpi_orb.showHoverEffect": "true",
                "nasa_mission_control.kpi_orb.animationSpeed": "normal"
