            "title": "Latency"
        },
        "viz_ber_orb": {
            "type": "nasa_mission_control.kpi_orb",
            "options": {
                "nasa_mission_control.kpi_orb.valueField": "value",
                "nasa_mission_control.kpi_orb.unitField": "unit",
