                "nasa_mission_control.kpi_orb.orbColor": "#C084FC",
                "nasa_mission_control.kpi_orb.warnThreshold": "0.005",
                "nasa_mission_control.kpi_orb.criticalThreshold": "0.008",
                "nasa_mission_control.kpi_orb.orbSize": "medium",
                "nasa_mission_control.kpi_orb.showUnit": "false",
                "nasa_mission_control.kpi_orb.showLabel": "true",
                "nasa_mission_control.kpi_orb.showHalo": "true",
                "nasa_mission_control.kpi_orb.decimals": "2",
                "nasa_mission_control.kpi_orb.themeMode": "dark",
                "nasa_mission_control.kpi_orb.showEntrance": "true",
                "nasa_mission_control.kpi_orb.flashCritical": "true",
                "nasa_mission_control.kpi_orb.showHoverEffect": "true",
                "nasa_mission_control.kpi_orb.animationSpeed": "normal"
            },
            "dataSources": {
                "primary": "ds_telemetry_ber"
            },
            "title": "Bit Error Rate"
        },
        "viz_signal_waveform": {
            "type": "nasa_mission_control.signal_waveform",
            "options": {
                "nasa_mission_control.signal_waveform.amplitudeField": "signal_dbm",
